 16→ALFPWorldMapPlayerController::ALFPWorldMapPlayerController()
 17→{
 18→	CameraOffset = FVector::ZeroVector;
 19→
 20→	// 创建世界地图编辑器组件
 21→	WorldMapEditorComponent = CreateDefaultSubobject<ULFPWorldMapEditorComponent>(TEXT("WorldMapEditorComponent"));
 22→}
 23→
 24→void ALFPWorldMapPlayerController::BeginPlay()
 25→{
 26→	Super::BeginPlay();
 27→
 28→	// 设置输入模式
 29→	FInputModeGameAndUI InputMode;
 30→	InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
 31→	InputMode.SetHideCursorDuringCapture(false);
 32→	SetInputMode(InputMode);
 33→	bShowMouseCursor = true;
 34→
 35→	// 设置 Enhanced Input
 36→	if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
 37→	{
 38→		if (DefaultInputMapping)
 39→		{
 40→			Subsystem->AddMappingContext(DefaultInputMapping, 0);
 41→		}
 42→	}
 43→
 44→	// 场景切换淡入效果
 45→	if (PlayerCameraManager)
 46→	{
 47→		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 48→		float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
 49→		PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
 50→	}
 51→
 52→	// 首帧跳过相机平滑插值
 53→	bSnapCameraNextFrame = true;
 54→}
 55→
 56→void ALFPWorldMapPlayerController::Tick(float DeltaTime)
 57→{
 58→	Super::Tick(DeltaTime);
 59→
 60→	if (bIsDragging)
 61→	{
 62→		DragTime += DeltaTime;
 63→	}
 64→
 65→	// 更新相机位置和旋转
 66→	// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
 67→	FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
 68→
 69→	// 相机旋转：俯视角
 70→	FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
 71→
 72→	// 平滑插值并设置
 73→	FRotator CurrentRotation = GetControlRotation();
 74→	if (bSnapCameraNextFrame)
 75→	{
 76→		SetControlRotation(TargetRotation);
 77→	}
 78→	else
 79→	{
 80→		SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
 81→	}
 82→
 83→	// 通过 Pawn 控制相机位置（如果有 Pawn）
 84→	if (APawn* ControlledPawn = GetPawn())
 85→	{
 86→		if (bSnapCameraNextFrame)
 87→		{
 88→			// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
 89→			ControlledPawn->SetActorLocation(TargetLocation);
 90→			bSnapCameraNextFrame = false;
 91→		}
 92→		else
 93→		{
 94→			FVector CurrentLocation = ControlledPawn->GetActorLocation();
 95→			ControlledPawn->SetActorLocation(
 96→				FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
 97→			);
 98→		}
 99→	}
100→}
101→
102→void ALFPWorldMapPlayerController::SetupInputComponent()
103→{
104→	Super::SetupInputComponent();
105→
106→	if (UEnhancedInputComponent* EnhancedInputComponent = Cast<UEnhancedInputComponent>(InputComponent))
107→	{
108→		// 基础操作
109→		EnhancedInputComponent->BindAction(ConfirmAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnConfirmAction);
110→		EnhancedInputComponent->BindAction(CancelAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCancelAction);
111→
112→		// 相机操作
113→		EnhancedInputComponent->BindAction(CameraPanAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraPan);
114→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnCameraDragStarted);
115→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraDragTriggered);
116→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCameraDragCompleted);
117→		EnhancedInputComponent->BindAction(CameraZoomAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraZoom);
118→
119→		// 编辑器切换
120→		EnhancedInputComponent->BindAction(ToggleEditorAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnToggleEditorAction);
121→	}
122→}
123→
124→// ============== 输入处理 ==============
125→
126→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
127→{
128→	bIsDragging = false;
129→	if (DragTime > DragThresholdTime)
130→	{
131→		DragTime = 0.f;
132→		return;
133→	}
134→	DragTime = 0.f;
135→
136→	// 编辑器模式优先处理
137→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
138→	{
139→		// 射线检测点击的节点
140→		FHitResult HitResult;
141→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
142→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
143→
144→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
145→
146→		switch (CurrentTool)
147→		{
148→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
149→			{
150→				// 射线投射到 Z=0 平面获取世界坐标
151→				FVector WorldOrigin, WorldDirection;
152→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
153→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
154→				{
155→					float T = -WorldOrigin.Z / WorldDirection.Z;
156→					FVector HitPoint = WorldOrigin + WorldDirection * T;
157→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
158→				}
159→			}
160→			break;
161→
162→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
163→			if (ClickedNode)
164→			{
165→				WorldMapEditorComponent->SelectNode(ClickedNode);
166→				WorldMapEditorComponent->RemoveSelectedNode();
167→			}
168→			break;
169→
170→		case ELFPWorldMapEditorTool::WMET_MoveNode:
171→			if (ClickedNode)
172→			{
173→				WorldMapEditorComponent->SelectNode(ClickedNode);
174→			}
175→			else if (WorldMapEditorComponent->GetSelectedNode())
176→			{
177→				// 移动到点击位置
178→				FVector WorldOrigin, WorldDirection;
179→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
180→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
181→				{
182→					float T = -WorldOrigin.Z / WorldDirection.Z;
183→					FVector HitPoint = WorldOrigin + WorldDirection * T;
184→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
185→				}
186→			}
187→			break;
188→
189→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
190→			if (ClickedNode)
191→			{
192→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
193→			}
194→			break;
195→
196→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
197→			if (ClickedNode)
198→			{
199→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
200→			}
201→			break;
202→
203→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
204→			if (ClickedNode)
205→			{
206→				WorldMapEditorComponent->SelectNode(ClickedNode);
207→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
208→			}
209→			break;
210→
211→		default:
212→			break;
213→		}
214→		return;
215→	}
216→
217→	// 游戏模式：棋子移动中屏蔽点击
218→	ALFPWorldMapManager* Manager = GetWorldMapManager();
219→	if (Manager && Manager->IsPawnMoving()) return;
220→
221→	// 游戏模式：点击节点移动或进入
222→	FHitResult HitResult;
223→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
224→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
225→
226→	if (ClickedNode)
227→	{
228→		if (!Manager || !Manager->GetPlayerState()) return;
229→
230→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
231→
232→		// 点击当前节点 → 进入节点
233→		if (ClickedNode->NodeID == CurrentNodeID)
234→		{
235→			EnterNode(ClickedNode);
236→			return;
237→		}
238→
239→		// 点击相邻可达节点 → 移动
240→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
241→		if (ReachableIDs.Contains(ClickedNode->NodeID))
242→		{
243→			MoveToNode(ClickedNode);
244→		}
245→		else
246→		{
247→			// 不可达，只选中
248→			SelectNode(ClickedNode);
249→		}
250→	}
251→}
252→
253→void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
254→{
255→	// 取消选中和可达高亮
