 10→{
 11→	TBT_Shop            UMETA(DisplayName = "商店"),
 12→	TBT_EvolutionTower  UMETA(DisplayName = "升华塔"),
 13→	TBT_Teleport        UMETA(DisplayName = "传送阵"),
 14→	TBT_QuestNPC        UMETA(DisplayName = "任务NPC"),
 15→	TBT_SkillNode       UMETA(DisplayName = "技能节点"),
 16→};
