	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
	int32 BrushBaseGoldReward = 0;

	// 基础食物奖励
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
	int32 BrushBaseFoodReward = 0;

	// 城镇建筑列表（分号分隔）
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Brush")
	FString BrushTownBuildingList;

