	BaseGoldReward = Row.BaseGoldReward;
	BaseFoodReward = Row.BaseFoodReward;
	EventID = Row.EventID;
	TownBuildingList = Row.TownBuildingList;
	ShopID = Row.ShopID;
	PrerequisiteNodeIDs = Row.PrerequisiteNodeIDs;

	SetActorLocation(FVector(Row.PosX, Row.PosY, 0.f));
}

