 30→	if (BaseFoodRewardInput) BaseFoodRewardInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnBaseFoodRewardChanged);
 31→	if (ShopIDInput) ShopIDInput->OnTextCommitted.AddDynamic(this, &ULFPWorldMapEditorWidget::OnShopIDChanged);
 32→
 33→	// 城镇建筑勾选框
 34→	if (TownCheck_Shop) TownCheck_Shop->OnCheckStateChanged.AddDynamic(this, &ULFPWorldMapEditorWidget::OnTownBuildingCheckChanged);
 35→	if (TownCheck_EvolutionTower) TownCheck_EvolutionTower->OnCheckStateChanged.AddDynamic(this, &ULFPWorldMapEditorWidget::OnTownBuildingCheckChanged);
 36→	if (TownCheck_Teleport) TownCheck_Teleport->OnCheckStateChanged.AddDynamic(this, &ULFPWorldMapEditorWidget::OnTownBuildingCheckChanged);
