 41→	if (SaveWorldMapButton) SaveWorldMapButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnSaveClicked);
 42→	if (LoadWorldMapButton) LoadWorldMapButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnLoadClicked);
 43→	if (NewWorldMapButton) NewWorldMapButton->OnClicked.AddDynamic(this, &ULFPWorldMapEditorWidget::OnNewMapClicked);
 44→
 45→	// 填充节点类型下拉框
 46→	if (NodeTypeComboBox)
 47→	{
 48→		NodeTypeComboBox->ClearOptions();
 49→		NodeTypeComboBox->AddOption(TEXT("WNT_Battle"));
 50→		NodeTypeComboBox->AddOption(TEXT("WNT_Event"));
 51→		NodeTypeComboBox->AddOption(TEXT("WNT_Shop"));
 52→		NodeTypeComboBox->AddOption(TEXT("WNT_Town"));
 53→		NodeTypeComboBox->AddOption(TEXT("WNT_Boss"));
 54→		NodeTypeComboBox->AddOption(TEXT("WNT_QuestNPC"));
 55→		NodeTypeComboBox->AddOption(TEXT("WNT_SkillNode"));
 56→		NodeTypeComboBox->AddOption(TEXT("WNT_EvolutionTower"));
 57→		NodeTypeComboBox->SetSelectedOption(TEXT("WNT_Battle"));
 58→	}
 59→
 60→	// 默认值
 61→	if (StarRatingInput) StarRatingInput->SetText(FText::FromString(TEXT("1")));
 62→	if (CanEscapeCheckBox) CanEscapeCheckBox->SetIsChecked(true);
 63→	if (EdgeTurnCostInput) EdgeTurnCostInput->SetText(FText::FromString(TEXT("1")));
 64→	if (BaseGoldRewardInput) BaseGoldRewardInput->SetText(FText::FromString(TEXT("0")));
 65→	if (BaseFoodRewardInput) BaseFoodRewardInput->SetText(FText::FromString(TEXT("0")));
 66→	if (ShopIDInput) ShopIDInput->SetText(FText::GetEmpty());
