		TArray<AActor*> Managers;
		UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPWorldMapManager::StaticClass(), Managers);
		if (Managers.Num() > 0)
		{
			CachedWorldMapManager = Cast<ALFPWorldMapManager>(Managers[0]);
		}
	}
	return CachedWorldMapManager;
}

